import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;

@SpringBootApplication
public class MfaBackupCodesApplication {

    public static void main(String[] args) {
        SpringApplication.run(MfaBackupCodesApplication.class, args);
    }
}

@Service
public class UserService {

    @Autowired
    private UserRepository userRepository;

    public User enableMfa(User user) {
        // Generate backup codes and store them in the database
        List<String> backupCodes = generateBackupCodes();
        user.setBackupCodes(backupCodes);
        userRepository.save(user);
        return user;
    }

    private List<String> generateBackupCodes() {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            codes.add(generateCode());
        }
        return codes;
    }

    private String generateCode() {
        // Generate a random 6-digit code
        Random rand = new Random();
        int number = rand.nextInt(900000) + 100000; // 6-digit number between 100000 and 999999
        return String.format("%06d", number);
    }
}

@RestController
public class UserController {

    @Autowired
    private UserService userService;

    @PostMapping("/enable-mfa")
    public User enableMfa(@RequestBody User user) {
        return userService.enableMfa(user);
    }

    @PostMapping("/login-with-backup-code")
    public ResponseEntity<String> loginWithBackupCode(@RequestBody LoginRequest request) {
        // Check the backup code against the database and authenticate the user
        boolean isValid = userService.validateBackupCode(request.getUsername(), request.getCode());
        if (isValid) {
            return ResponseEntity.ok("Login successful");
        } else {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid backup code");
        }
    }

    private boolean validateBackupCode(String username, String code) {
        // Retrieve user from the database and check the backup codes
        User user = userRepository.findByUsername(username);
        if (user != null && user.getBackupCodes().contains(code)) {
            return true;
        }
        return false;
    }
}

